mapper.select:
SELECT r.roadway,a.group_no,a.borehole_no,a.borehole_code,a.pull_drill_date,d.angle AS desangle,a.angle AS actangle,d.inclination_angle AS desinclinationangle, a.inclination_angle AS actInclinationangle,d.depth_1st_coal_seam_start AS desCoalDepth,a.depth_1st_coal_seam_start AS actCoalDepth, CONCAT(a.depth_1st_coal_seam_start,'-',a.depth_1st_coal_seam_end) AS seecoalcase,a.adjacent_borehole_no,a.distance_adjacent_borehole, CONCAT('岩1:',a.depth_1st_rock_seam_start,'-',a.depth_1st_rock_seam_end,',煤1:',a.depth_1st_coal_seam_start,'-',a.depth_1st_coal_seam_end,',岩2:',a.depth_2st_rock_seam_start, '-',a.depth_2st_rock_seam_end,',煤2:',a.depth_2st_coal_seam_start,'-',a.depth_2st_coal_seam_end,',岩3:',a.depth_3st_rock_seam_start,'-',a.depth_3st_rock_seam_end) as seerockcoalcase, ROUND(a.hole_altitude,2) AS holeAltitude,n.navigation_point_name,a.person_checking_site as personchecking, a.distance_to_navigation_point,a.distance_to_centralline_tunnel,a.person_construction,a.chargehand, a.sealing_material,ROUND((a.punching_paragraph2-a.punching_paragraph1),2)AS lengthFlushing,(d.inclination_angle-a.inclination_angle) AS ErrInclinationAngle, a.actual_coal_amount_flushed,a.completion_ratio_flushed_coal,dp.gas_concentration,dp.negative_pressure from t_bk_act_borehole_info a LEFT JOIN t_designed_borehole d ON CONCAT(a.roadway_id,a.group_no,a.borehole_no) =CONCAT(d.roadway_id,d.group_no,d.borehole_no) LEFT JOIN t_navigation_point n ON a.navigation_point_id =n.id LEFT JOIN t_drainage_parameter dp ON dp.borehole_Id=a.id LEFT JOIN t_sealing_grouting s ON a.id=s.borehole_id LEFT JOIN t_roadway r ON r.id = a.roadway_id LEFT JOIN t_purpose_borehole p ON p.id = a.purpose_borehole_id where 1=1 and dp.beginningcon=1
and a.roadway_id = #{roadwayId}
AND a.group_no IN
#{item}
AND a.purpose_borehole_id IN
#{item}
AND a.checking_date BETWEEN #{startdate} AND #{enddate}
